# Shapes module - implements interfaces from types_module
# Demonstrates cross-module interface implementation and inheritance

from types_module import Color, IShape, IScalable, Point

class Rectangle(IShape, IScalable):
    width: float
    height: float
    rect_color: Color

    def __init__(self, width: float, height: float, rect_color: Color):
        self.width = width
        self.height = height
        self.rect_color = rect_color

    @override
    def area(self) -> float:
        return self.width * self.height

    @override
    def describe(self) -> str:
        return f"Rectangle(width={self.width}, height={self.height})"

    @override
    def scale(self, factor: float) -> None:
        self.width = self.width * factor
        self.height = self.height * factor

    def get_color_name(self) -> str:
        return self.rect_color.name

class Circle(IShape, IScalable):
    radius: float
    center: Point

    def __init__(self, radius: float, center: Point):
        self.radius = radius
        self.center = center

    @override
    def area(self) -> float:
        return 3.14159 * self.radius ** 2

    @override
    def describe(self) -> str:
        return f"Circle(radius={self.radius}, center=({self.center.x}, {self.center.y}))"

    @override
    def scale(self, factor: float) -> None:
        self.radius = self.radius * factor

class Square(Rectangle):
    def __init__(self, side: float, square_color: Color):
        super().__init__(side, side, square_color)

