# Utils module - provides helper functions and tracking
# Uses types from types_module

from types_module import Color, Point

@static
class ShapeTracker:
    shapes_created: int = 0

    @static
    def increment() -> None:
        ShapeTracker.shapes_created = ShapeTracker.shapes_created + 1

    @static
    def get_count() -> int:
        return ShapeTracker.shapes_created

    @static
    def reset() -> None:
        ShapeTracker.shapes_created = 0

def create_point(x: float, y: float) -> Point:
    ShapeTracker.increment()
    return Point(x, y)

def create_default_color() -> Color:
    return Color.BLUE

def format_area(shape_name: str, area: float) -> str:
    return f"{shape_name} has area {area:.2f}"
